const body = $input.first().json;
const action = body.action; // 'register' | 'magic-link' | 'oauth-callback'

const responses = {
  register: {
    url: 'https://{{ $env.SUPABASE_PROJECT_ID }}.supabase.co/auth/v1/signup',
    method: 'POST',
    headers: { 'apikey': '{{ $env.SUPABASE_ANON_KEY }}', 'Content-Type': 'application/json' },
    body: { email: body.email, password: body.password, data: { full_name: body.name } }
  },
  'magic-link': {
    url: 'https://{{ $env.SUPABASE_PROJECT_ID }}.supabase.co/auth/v1/otp',
    method: 'POST',
    headers: { 'apikey': '{{ $env.SUPABASE_ANON_KEY }}', 'Content-Type': 'application/json' },
    body: { email: body.email, options: { email_redirect_to: body.redirect_to || 'https://yourapp.com/callback' } }
  }
};

return [{ json: { action, ...responses[action] || responses.register } }];
